import { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import romWht from '../assets/icons/rom_wht.png'

type OnboardingPhase = 1 | 2 | 3 | 4 | 'idle'

interface RomOnboardingProps {
  currentUser: string | null
  isCreateSelected: boolean
}

export function RomOnboarding({ currentUser, isCreateSelected }: RomOnboardingProps) {
  const [phase, setPhase] = useState<OnboardingPhase>(1)

  // Phase transitions based on props
  useEffect(() => {
    if (!currentUser) {
      setPhase(1)
    } else if (currentUser && phase === 1) {
      setPhase(2)
    }
  }, [currentUser, phase])

  useEffect(() => {
    if (isCreateSelected && phase === 3) {
      setPhase(4)
    }
  }, [isCreateSelected, phase])

  const handleSkip = () => setPhase('idle')
  const handleContinue = () => setPhase(3)

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      justifyContent: 'center',
      width: '100%',
      position: 'relative',
    }}>
      {/* Dialogue Bubble */}
      <AnimatePresence mode="wait">
        {phase !== 'idle' && (
          <motion.div
            key={phase}
            initial={{ opacity: 0, y: 10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: -10, scale: 0.95 }}
            transition={{ type: 'spring', stiffness: 400, damping: 30 }}
            style={{
              position: 'absolute',
              bottom: '100%',
              marginBottom: '20px',
              backgroundColor: 'rgba(20, 20, 20, 0.9)',
              border: '1px solid rgba(255, 255, 255, 0.2)',
              borderRadius: '16px',
              padding: '16px 20px',
              width: 'max-content',
              maxWidth: '85vw',
              textAlign: 'center',
              boxShadow: '0 8px 32px rgba(0, 0, 0, 0.5)',
              zIndex: 10,
              pointerEvents: 'auto',
            }}
          >
            {/* Tail */}
            <div style={{
              position: 'absolute',
              bottom: '-8px',
              left: '50%',
              transform: 'translateX(-50%) rotate(45deg)',
              width: '16px',
              height: '16px',
              backgroundColor: 'rgba(20, 20, 20, 0.9)',
              borderRight: '1px solid rgba(255, 255, 255, 0.2)',
              borderBottom: '1px solid rgba(255, 255, 255, 0.2)',
              zIndex: -1,
            }} />

            {/* Texts */}
            {phase === 1 && (
              <p style={{ margin: 0, fontSize: '14px', lineHeight: 1.5, color: '#e5e7eb', maxWidth: '300px' }}>
                <span style={{ color: '#9ca3af', fontStyle: 'italic', display: 'block', marginBottom: '4px' }}>*Beep... whirrr...*</span>
                Hello, Human! I am ROM. This place is a bit empty right now... but with your help, we can bring back the light. Please, <strong>sign in</strong> so we can begin our mission.
              </p>
            )}

            {phase === 2 && (
              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px', alignItems: 'center', maxWidth: '320px' }}>
                <p style={{ margin: 0, fontSize: '14px', lineHeight: 1.5, color: '#e5e7eb' }}>
                  <span style={{ color: '#4ade80', fontWeight: 'bold', display: 'block', marginBottom: '4px' }}>System recognized!</span>
                  I am so glad you&apos;re here. Would you like me to show you around and help you start your journey?
                  <br />
                  <span style={{ fontSize: '12px', color: '#9ca3af', marginTop: '4px', display: 'inline-block' }}>(Or would you prefer to explore the ruins alone?)</span>
                </p>
                <div style={{ display: 'flex', gap: '8px', width: '100%' }}>
                  <button
                    onClick={handleSkip}
                    style={{ flex: 1, padding: '8px 12px', borderRadius: '8px', border: '1px solid rgba(255,255,255,0.2)', background: 'transparent', color: '#e5e7eb', fontSize: '12px', cursor: 'pointer', transition: 'all 0.2s' }}
                    onMouseEnter={e => e.currentTarget.style.backgroundColor = 'rgba(255,255,255,0.1)'}
                    onMouseLeave={e => e.currentTarget.style.backgroundColor = 'transparent'}
                  >
                    Skip
                  </button>
                  <button
                    onClick={handleContinue}
                    style={{ flex: 1, padding: '8px 12px', borderRadius: '8px', border: 'none', background: '#2563eb', color: 'white', fontSize: '12px', fontWeight: 'bold', cursor: 'pointer', transition: 'all 0.2s' }}
                    onMouseEnter={e => e.currentTarget.style.backgroundColor = '#3b82f6'}
                    onMouseLeave={e => e.currentTarget.style.backgroundColor = '#2563eb'}
                  >
                    Continue
                  </button>
                </div>
              </div>
            )}

            {phase === 3 && (
              <p style={{ margin: 0, fontSize: '14px', lineHeight: 1.5, color: '#e5e7eb', maxWidth: '340px', textAlign: 'left' }}>
                To save the world, we must communicate. You have two choices:
                <br /><br />
                <span style={{ color: '#fbbf24', fontWeight: 'bold' }}>Explore:</span> Visit public servers to see how other humans have built their civilizations. (Select a server from the left)
                <br /><br />
                <span style={{ color: '#60a5fa', fontWeight: 'bold' }}>Create:</span> Build your own &quot;Minecraft-style&quot; server and bring a ROM like me to life. (Click &quot;CRÉER&quot; on the right)
              </p>
            )}

            {phase === 4 && (
              <p style={{ margin: 0, fontSize: '14px', lineHeight: 1.5, color: '#e5e7eb', maxWidth: '360px', textAlign: 'left' }}>
                Creating a home for a ROM is a big responsibility!
                To keep your server alive 24/7, I suggest a <strong>Jetson NANO Dev Kit</strong>.
                <br /><br />
                <span style={{ color: '#a78bfa', fontWeight: 'bold' }}>Technical Specs:</span> You will need <strong>1TB of space</strong> to store all the world&apos;s memos.
                This hardware becomes the &apos;heart&apos; of your Forom. It&apos;s how you bring life to a ROM of your very own!
                <br /><br />
                <span style={{ color: '#9ca3af', fontStyle: 'italic' }}>*Happy whirring sounds.*</span>
              </p>
            )}
          </motion.div>
        )}
      </AnimatePresence>

      {/* ROM Character */}
      <motion.img
        src={romWht}
        alt="ROM Guardian"
        animate={{
          y: phase === 'idle' ? 0 : [0, -5, 0],
        }}
        transition={{
          repeat: phase === 'idle' ? 0 : Infinity,
          duration: 2,
          ease: 'easeInOut'
        }}
        style={{
          width: 'clamp(52px, 7vw, 110px)',
          height: 'clamp(52px, 7vw, 110px)',
          objectFit: 'contain',
          marginBottom: 'clamp(24px, 4vh, 56px)',
          flexShrink: 0,
          opacity: phase === 'idle' ? 0.6 : 1,
          filter: phase !== 'idle' ? 'drop-shadow(0 0 12px rgba(255,255,255,0.4))' : 'none',
        }}
      />
    </div>
  )
}
